public class FixedZipFile extends ZipFile {

    public FixedZipFile(InputStream in) throws IOException {
        super(in);
    }

    @Override
    protected void resolveLocalFileHeaderData(Map<ZipArchiveEntry, NameAndComment> entriesWithoutUTF8Flag) throws IOException {
        List<ZipArchiveEntry> entryList = new ArrayList<>(this.entries.size());
        for (Iterator<ZipArchiveEntry> iterator = this.entries.keySet().iterator(); iterator.hasNext(); ) {
            ZipArchiveEntry ze = iterator.next();
            entryList.add(ze);
            iterator.remove();
        }
        super.resolveLocalFileHeaderData(entriesWithoutUTF8Flag);
        for (ZipArchiveEntry ze : entryList) {
            this.entries.put(ze, this.entries.get(ze));
        }
    }
}

